from pathlib import Path from typing import Any, Dict
from dita_package_processor.execution.models import ExecutionActionResult from dita_package_processor.execution.registry import ExecutionHandler
class RouteSpecialTopicHandler(ExecutionHandler): action_type = "com.acme.route_special_topic"
def execute(self, *, action: Dict[str, Any], source_root: Path, sandbox, policy): action_id = str(action.get("id", "<unknown>")) params = action.get("parameters", {}) dry_run = bool(action.get("dry_run", False))
# Validate required fields before path operations. if "source_path" not in params or "target_path" not in params: return ExecutionActionResult( action_id=action_id, status="failed", handler=self.__class__.__name__, dry_run=dry_run, message="Missing required parameters: source_path, target_path", )
if dry_run: return ExecutionActionResult( action_id=action_id, status="skipped", handler=self.__class__.__name__, dry_run=True, message="Dry-run: custom handler skipped", )
